def transform(input_grid):
    # Create a copy of the input grid
    output_grid = [row[:] for row in input_grid]
    rows = len(input_grid)
    cols = len(input_grid[0])

    # Use flood fill to identify enclosed regions
    # First, mark all 0s that are connected to the border
    visited = [[False] * cols for _ in range(rows)]

    # Start from border cells that are 0
    queue = []
    for i in range(rows):
        for j in range(cols):
            if (i == 0 or i == rows-1 or j == 0 or j == cols-1) and input_grid[i][j] == 0:
                queue.append((i, j))

    # Flood fill from border 0s
    while queue:
        i, j = queue.pop(0)
        if visited[i][j]:
            continue
        visited[i][j] = True

        # Check all 4 directions
        for di, dj in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < rows and 0 <= nj < cols and not visited[ni][nj] and input_grid[ni][nj] == 0:
                queue.append((ni, nj))

    # Now, any 0 that is not visited is enclosed by 3s
    for i in range(rows):
        for j in range(cols):
            if input_grid[i][j] == 0 and not visited[i][j]:
                output_grid[i][j] = 4

    return output_grid
